            "x": [int(v) for v in PILOT_COUNTS],
            "proposed": [float(v) for v in sec_proposed],
            "baseline_name": [float(v) for v in sec_baseline],
            "x_label": "Number of pilots (fixed SNR=15 dB)",
            "y_label": "NMSE (dB)"
        },
        "delay_domain_example": delay_example
    }

